mapper.select:
SELECT r.seckill_goods_id AS seckillGoodsId, t.tag_name AS tagName FROM osh_seckill_goods_tag t INNER JOIN osh_seckill_goods_tag_rel r ON t.id = r.tag_id WHERE r.seckill_goods_id IN
#{id}
AND (r.delete_flag = 0 OR r.delete_flag IS NULL) AND (t.delete_flag = 0 OR t.delete_flag IS NULL) ORDER BY r.seckill_goods_id ASC, t.sort_order ASC, t.id ASC
